146	    hide();
147	    onStart?.();
148	  }
149	
150	  function activate(el) {
151	    switch (el?.dataset.action) {
152	      case "start": startStory(); break;
153	      case "options": setScreen("options"); break;
154	      case "controls": setScreen("controls"); break;
155	      case "display": setScreen("display"); break;
156	      case "sound": setScreen("sound"); break;
157	      case "music-toggle": toggleMusic(); break;
158	      case "tv-toggle": toggleTv(); break;
159	      case "back": back(); break;
160	    }
161	  }
162	
